const toggle=document.querySelector(".nav-toggle"),menu=document.querySelector(".nav-menu");toggle.addEventListener("click",()=>{const e="true"===toggle.getAttribute("aria-expanded");toggle.setAttribute("aria-expanded",!e),menu.classList.toggle("active")});const cardBoxes=document.querySelectorAll(".card-hover-box");cardBoxes.forEach(e=>{const t=e.querySelector(".card-primary"),r=e.querySelector(".card-secondary");t.addEventListener("mouseenter",()=>{r.style.maxHeight=r.scrollHeight+"px",r.style.opacity="1",r.style.transform="translateY(0)"}),t.addEventListener("mouseleave",()=>{r.style.maxHeight="0",r.style.opacity="0",r.style.transform="translateY(-10px)"})});const observer=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting?(e.target.classList.add("in-view"),e.target.classList.remove("out-view")):(e.target.classList.remove("in-view"),e.target.classList.add("out-view"))})},{threshold:.35});document.querySelectorAll(".element-appear").forEach(e=>observer.observe(e)),document.querySelectorAll(".element-appear-right").forEach(e=>observer.observe(e)),document.querySelectorAll(".element-appear-left").forEach(e=>observer.observe(e));